using Godot; using Godot.Collections; using System; using System.Text.Json; using System.Collections.Generic; using System.Linq; using System.Text; using System.Text.Json; using System.Threading.Tasks; using Satsuki.Tools.Converters;  namespace Satsuki.Models {     [GlobalClass]     public partial class StageResource : Resource     {         [Export]         public int Id { get; set; }         [Export]         public string Name { get; set; }         [Export]         public string SceneName { get; set; }         [Export]         public string ScenePath { get; set; }         [Export]         public LobbyInfo LobbyInfo { get; set; } = new LobbyInfo();         [Export]         public StageInfo StageInfo { get; set; } = new StageInfo();         [Export]         public string CreatedAt { get; set; }         [Export]         public string SavedAt { get; set; }          public StageResource()         {             Id = 0;             Name = "";             SceneName = "";             ScenePath = "";             LobbyInfo = new LobbyInfo();             StageInfo = new StageInfo();             CreatedAt = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");             SavedAt = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");         }          public void Load(int id)         {             var stageResource = GetStageById(id);             if (stageResource != null)             {                 this.Id = stageResource.Id;                 this.Name = stageResource.Name;                 this.SceneName = stageResource.SceneName;                 this.ScenePath = stageResource.ScenePath;                 this.LobbyInfo = stageResource.LobbyInfo;                 this.StageInfo = stageResource.StageInfo;                 this.CreatedAt = stageResource.CreatedAt;                 this.SavedAt = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");             }         }          private int SaveInDb()         {             int result = -1;             using (var dbManager = new SqliteDbManager())             {                 dbManager.OpenConnection();                 using (var connection = dbManager.GetConnection())                 {                     using (var command = connection.CreateCommand())                     {                         var LobbyRsc = JsonSerializer.Serialize(LobbyInfoConverter.ConvertFrom(this.LobbyInfo));                         var StageRsc = JsonSerializer.Serialize(StageInfoConverter.ConvertFrom(this.StageInfo));                         GD.Print(JsonSerializer.Serialize(LobbyRsc));
                        GD.Print(JsonSerializer.Serialize(StageRsc));                         GD.Print(this.ScenePath);                         GD.Print("Test");                         if (this.Id == 0)
                        {
                            command.CommandText =
                           @"INSERT INTO Stages (NAME,SCENE_NAME,SCENE_PATH,LOBBY_RSC,STAGE_RSC) VALUES (@name,@sceneName,@scenePath,@lobbyRsc,@stageRsc) RETURNING Id;";
                        }                         else
                        {
                            command.CommandText =
                                $@"UPDATE Stages SET NAME = @name,SCENE_NAME = @sceneName,SCENE_PATH = @scenePath,LOBBY_RSC = @lobbyRsc,STAGE_RSC = @stageRsc WHERE Stages.Id = @id";
                            command.Parameters.AddWithValue("@id", this.Id);
                        }                         command.Parameters.AddWithValue("@name", this.Name);
                        command.Parameters.AddWithValue("@sceneName", this.SceneName);
                        command.Parameters.AddWithValue("@scenePath", this.ScenePath);
                        command.Parameters.AddWithValue("@lobbyRsc", LobbyRsc);
                        command.Parameters.AddWithValue("@stageRsc", StageRsc);                         GD.Print(command.CommandText);                         var reader = command.ExecuteReader();                         while (reader.Read())
                        {
                            result = reader.GetInt32(0);
                        }                      }                 }                 dbManager.CloseConnection();                 return result;             }         }          private StageResource GetStageById(int id)         {             StageResource result = null;              using (var dbManager = new SqliteDbManager())             {                 dbManager.OpenConnection();                 using (var connection = dbManager.GetConnection())                 {                     using (var command = connection.CreateCommand())                     {                         command.CommandText = $"SELECT ID,NAME,SCENE_NAME,SCENE_PATH,LOBBY_RSC,STAGE_RSC FROM Stages WHERE ID = @id;";                         command.Parameters.AddWithValue("@id", id);                         using (var reader = command.ExecuteReader())                         {                             if (reader.Read())                             {                                 result = new StageResource                                 {                                     Id = reader.GetInt32(0),                                     Name = reader.GetString(1),                                     SceneName = reader.GetString(2),                                     ScenePath = reader.GetString(3),                                     LobbyInfo = LobbyInfoConverter.ConvertTo(JsonSerializer.Deserialize<LobbyInfoResource>(reader.GetString(4))),                                     StageInfo = StageInfoConverter.ConvertTo(JsonSerializer.Deserialize<StageInfoResource>(reader.GetString(5)))                                 };                             }                         }                     }                 }                 dbManager.CloseConnection();             }             return result;         }          public bool Save()         {             this.Id = SaveInDb();             return true;         }          public bool Save(string path)         {             try             {                 ResourcePath = path;                 var error = ResourceSaver.Save(this, path, ResourceSaver.SaverFlags.ChangePath);                  if (error == Error.Ok)                 {                     GD.Print($"StageResource sauvegardee: {path}");                     var file = FileAccess.Open(path, FileAccess.ModeFlags.Read);                     if (file != null)                     {                         var firstLine = file.GetLine();                         file.Close();                         GD.Print($"DEBUG: Premiere ligne du fichier sauvegarde: '{firstLine}'");                     }                     return true;                 }                 else                 {                     GD.PrintErr($"Erreur sauvegarde StageResource: {error}");                     return false;                 }             }             catch (Exception ex)             {                 GD.PrintErr($"Exception sauvegarde: {ex.Message}");                 return false;             }         }          public static StageResource Load(string path)         {             try             {                 if (!ResourceLoader.Exists(path))                 {                     GD.PrintErr($"Fichier introuvable: {path}");                     return null;                 }                  var raw = ResourceLoader.Load(path, "", ResourceLoader.CacheMode.Ignore);                 if (raw is StageResource resource)                 {                     return resource;                 }                 return null;             }             catch (Exception ex)             {                 GD.PrintErr($"Exception chargement: {ex.Message}");                 return null;             }         }     } }